import (
	"context"
	"fmt"
	"time"

	"github.com/go-redis/redis/v8"
)

func main() {
	ctx := context.Background()

	// Connect to Redis
	rdb := redis.NewClient(&redis.Options{
		Addr:     "localhost:6379",
		Password: "", // no password set
		DB:       0,  // use default DB
	})

	// Subscribe to Redis notifications for expired keys
	ps := rdb.Subscribe(ctx, "__keyevent@0__:expired")
	defer ps.Close()

	// Start a goroutine to handle the notifications
	go func() {
		for {
			msg, err := ps.ReceiveMessage(ctx)
			if err != nil {
				panic(err)
			}
			// The "msg.Channel" field will be "__keyevent@0__:expired"
			// and the "msg.Payload" field will be the expired key
			fmt.Printf("Expired key: %s\n", msg.Payload)
			// Process expired SMPP segments...
		}
	}()

	// Create a sample SMPP segment with a validity time of 30 seconds
	smppSegment := "Hello world!"
	validityTime := 30 * time.Second

	// Save the SMPP segment in Redis with a TTL
	key := "smpp-segment-123"
	err := rdb.SetEX(ctx, key, smppSegment, validityTime).Err()
	if err != nil {
		panic(err)
	}

	// Wait for SMPP segment to expire...
	select {}
