func main() {
	ctx := context.Background()

	// Connect to MySQL
	db, err := sql.Open("mysql", "user:password@tcp(localhost:3306)/sms_db")
	if err != nil {
		panic(err)
	}
	defer db.Close()

	// Connect to Redis
	rdb := redis.NewClient(&redis.Options{
		Addr:     "localhost:6379",
		Password: "", // no password set
		DB:       0,  // use default DB
	})

	// Create a sample SMPP segment with a validity time of 30 seconds
	smppSegment := "Hello world!"
	validityTime := 30 * time.Second

	// Save the SMPP segment in Redis with a TTL
	key := "smpp-segment-123"
	err = rdb.SetEX(ctx, key, smppSegment, validityTime).Err()
	if err != nil {
		panic(err)
	}

	// Save the SMPP segment in MySQL with the same validity time
	expireAt := time.Now().Add(validityTime)
	_, err = db.ExecContext(ctx, "INSERT INTO sms_segments (segment, expire_at) VALUES (?, ?)", smppSegment, expireAt)
	if err != nil {
		panic(err)
	}

	// Wait for SMPP segment to expire...
	select {}
}
